module multi_8bit(
    input [7:0] A,
    input [7:0] B,
    output reg [15:0] product
);

reg [15:0] partial_products [7:0];
reg [7:0] shift_reg;
reg [3:0] i;

always @(*) begin
    // Generate partial products
    for (i = 0; i < 8; i = i + 1) begin
        partial_products[i] = (B[i]) ? (A << i) : 16'b0;
    end

    // Accumulate partial products
    product = 16'b0;
    for (i = 0; i < 8; i = i + 1) begin
        product = product + partial_products[i];
    end
end

endmodule
